const input = $json;

// Datos base
const normalizedInput = input.input || input || {};
const supervisor = input.supervisor || {};
const marketData = input.market_analysis || {};
const bmcData = input.bmc || {};
const strategyData = input.strategy || {};
const financeData = input.finance || {};
const risksData = Array.isArray(input.risks) ? input.risks : [];
const roadmapData = input.roadmap || {};
const verdictData = input.verdict?.verdict || input.verdict || {};
const activitiesData = input.activities?.activities || input.activities || [];
const kanbanData = input.kanban || { columns: [], cards: [] };
const ganttData = input.gantt || { project_start: null, tasks: [] };

// Summary
const summary = {
  executive_summary:
    verdictData?.executive_summary ||
    "Análisis estratégico generado por Innexia AI Strategy Engine.",
  key_findings: [],
  priority_actions: []
};

if (Array.isArray(marketData?.opportunities) && marketData.opportunities.length) {
  summary.key_findings.push(
    `Se identificaron ${marketData.opportunities.length} oportunidades principales.`
  );
}

if (Array.isArray(risksData) && risksData.length) {
  summary.key_findings.push(
    `Se identificaron ${risksData.length} riesgos relevantes.`
  );
}

if (Array.isArray(activitiesData) && activitiesData.length) {
  summary.priority_actions.push(
    ...activitiesData
      .slice(0, 5)
      .map(a => a.title || a.activity_id)
      .filter(Boolean)
  );
}

const consolidated = {
  request_id: input.request_id || normalizedInput.request_id || null,
  project_name: input.project_name || normalizedInput.project_name || null,
  workflow_version: 'v5.3',
  status: 'completed',
  language: input.language || normalizedInput.language || 'es',
  input: normalizedInput,
  supervisor,
  market_analysis: marketData,
  bmc: bmcData,
  strategy: strategyData,
  finance: financeData,
  risks: risksData,
  roadmap: roadmapData,
  verdict: verdictData,
  activities: activitiesData,
  kanban: kanbanData,
  gantt: ganttData,
  summary,
  meta: {
    created_at: normalizedInput?.meta?.created_at || input?.meta?.created_at || null,
    completed_at: new Date().toISOString(),
    modules_executed: Object.entries({
      supervisor: !!supervisor && Object.keys(supervisor).length > 0,
      market_intelligence: !!marketData && Object.keys(marketData).length > 0,
      bmc: !!bmcData && Object.keys(bmcData).length > 0,
      strategy: !!strategyData && Object.keys(strategyData).length > 0,
      finance: !!financeData && Object.keys(financeData).length > 0,
      risks: Array.isArray(risksData) && risksData.length > 0,
      roadmap: !!roadmapData && Object.keys(roadmapData).length > 0,
      verdict: !!verdictData && Object.keys(verdictData).length > 0,
      activities: Array.isArray(activitiesData) && activitiesData.length > 0,
      kanban: !!kanbanData && Object.keys(kanbanData).length > 0,
      gantt: !!ganttData && Object.keys(ganttData).length > 0
    })
      .filter(([_, ran]) => ran)
      .map(([name]) => name),
    modules_failed: []
  }
};

return [{ json: consolidated }];
